solutions.cpp:
#include <iostream>

using namespace std;
class Solution {
public:
    bool solve(vector<int>& nums, int k) {
        return bool(nums.size() >= k);
    }
};

int main() {
    int n, k;
    cin >> n >> k;
    vector<int> nums(n);
    for (int i = 0; i < n; i++)
        cin >> nums[i];
    Solution solution;
    cout << (solution.solve(nums, k) ? "true" : "false") << endl;
    return 0;
}
